class Solution:
    def zeroFilledSubarray(self, nums):
        total = 0
        n = len(nums)
        i = 0
        while i < n:
            if nums[i] == 0:
                j = i
                while j < n and nums[j] == 0:
                    j += 1
                k = j - i
                total += k * (k + 1) // 2
                i = j
            else:
                i += 1
        return total

